'use strict';
// Adds ~120 new Mistake Clinic questions (topics 5-8), IDs fr-1345 to fr-1464
const fs = require('fs');
const path = require('path');

const dataPath = path.join(__dirname, '..', 'french-data.js');
let src = fs.readFileSync(dataPath, 'utf8');
const patched = src.replace(/window\./g, 'global.');
const g = {};
new Function('global', patched)(g);
const existing = g.FR_QUESTIONS;
const maxId = existing.reduce((m, q) => {
  const n = parseInt((q.id || '').replace('fr-', ''), 10);
  return n > m ? n : m;
}, 0);
console.log('Max existing ID: fr-' + maxId);

const NEW = [
  // ── fr-clinic-order (fr-1345–fr-1374) ───────────────────────────────────
  {"id":"fr-1345","topic":"fr-clinic-order","type":"mcq","q":"Which sentence has a word order error?","opts":["Je ne mange pas.","Je mange ne pas.","Il ne vient jamais.","Elle ne dit rien."],"ans":1,"exp":"'Ne' must come directly before the conjugated verb: 'Je ne mange pas.' 'Je mange ne pas' breaks this rule — 'ne' always precedes the verb.","lesson":"fr-clinic-order"},
  {"id":"fr-1346","topic":"fr-clinic-order","type":"typed","q":"Correct the word order: 'Je veux ne pas y aller.'","ans":"Je ne veux pas y aller.","alts":["je ne veux pas y aller","Je ne veux pas y aller"],"ignoreAccents":false,"exp":"'Ne...pas' wraps around the CONJUGATED verb. 'Veux' is the conjugated verb → Je ne veux pas. The infinitive 'y aller' follows after.","lesson":"fr-clinic-order"},
  {"id":"fr-1347","topic":"fr-clinic-order","type":"mcq","q":"Which word order is correct for 'Give it to me' (imperative)?","opts":["Donnez-moi-le.","Donnez-le-moi.","Le-moi donnez.","Moi-le donnez."],"ans":1,"exp":"Imperative pronoun order: direct object (le/la/les) before indirect (moi/toi/lui/nous/vous/leur). Donnez-le-moi = Give it to me.","lesson":"fr-clinic-order"},
  {"id":"fr-1348","topic":"fr-clinic-order","type":"gapfill","q":"Supply the missing 'ne' in formal negation:","template":"Il {0} vient pas souvent.","gaps":[{"options":["ne","n'","pas","non"],"answer":0}],"exp":"Standard negation: ne + verb + pas. 'Ne' goes before the verb. Without 'ne' is informal spoken French — in writing, always include it.","lesson":"fr-clinic-order"},
  {"id":"fr-1349","topic":"fr-clinic-order","type":"typed","q":"Translate: 'I don't eat meat.'","ans":"Je ne mange pas de viande.","alts":["je ne mange pas de viande","Je ne mange pas de viande"],"ignoreAccents":false,"exp":"Negation: ne + mange + pas. After negation, 'de la viande' → 'de viande'. Two rules in one: word order (ne...pas) and article change.","lesson":"fr-clinic-order"},
  {"id":"fr-1350","topic":"fr-clinic-order","type":"mcq","q":"Why is 'Je le veux pas' incorrect in formal writing?","opts":["'Le' is in the wrong position.","The 'ne' is missing: 'Je ne le veux pas'.","'Veux' should be 'voudrais'.","The object pronoun should be 'la'."],"ans":1,"exp":"Formal French requires both 'ne' and 'pas'. 'Je ne le veux pas.' Note: 'le' (direct object pronoun) correctly goes before the verb in statements.","lesson":"fr-clinic-order"},
  {"id":"fr-1351","topic":"fr-clinic-order","type":"mcq","q":"Which question form is the most formal?","opts":["Tu viens ?","Est-ce que tu viens ?","Viens-tu ?","T'as vu ?"],"ans":2,"exp":"Inversion (Viens-tu ?) is the most formal question form. 'Est-ce que' is standard. Rising intonation ('Tu viens ?') is informal. 'T'as vu' is very informal/argot.","lesson":"fr-clinic-order"},
  {"id":"fr-1352","topic":"fr-clinic-order","type":"gapfill","q":"Supply the missing 'ne' before a vowel:","template":"Je {0} comprends rien.","gaps":[{"options":["n'","ne","pas","non"],"answer":0}],"exp":"Before a vowel, 'ne' elides to 'n'': je n'comprends pas → je ne comprends rien. Actually: ne + vowel → n'. 'Ne...rien' = nothing.","lesson":"fr-clinic-order"},
  {"id":"fr-1353","topic":"fr-clinic-order","type":"typed","q":"Rewrite with correct formal negation: 'Je sais pas la réponse.'","ans":"Je ne sais pas la réponse.","alts":["je ne sais pas la réponse","Je ne sais pas la réponse"],"ignoreAccents":false,"exp":"'Ne' must not be dropped in formal/written French. Je ne sais pas = I don't know. Dropping 'ne' is a feature of informal spoken French.","lesson":"fr-clinic-order"},
  {"id":"fr-1354","topic":"fr-clinic-order","type":"mcq","q":"Where does 'souvent' (often) typically go in a simple sentence?","opts":["Before the subject","After the conjugated verb","Before the conjugated verb","At the end only when emphasised"],"ans":1,"exp":"Short adverbs of frequency go after the conjugated verb: Je mange souvent ici. In compound tenses, they go between auxiliary and past participle: J'ai souvent mangé ici.","lesson":"fr-clinic-order"},
  {"id":"fr-1355","topic":"fr-clinic-order","type":"mcq","q":"Which word order is correct in a statement with two object pronouns?","opts":["Il le me donne.","Il me le donne.","Il donne le me.","Il me donne le."],"ans":1,"exp":"In statements: indirect object (me/te/lui/nous/vous/leur) before direct object (le/la/les). 'Il me le donne' = He gives it to me. Imperative reverses this order.","lesson":"fr-clinic-order"},
  {"id":"fr-1356","topic":"fr-clinic-order","type":"gapfill","q":"Form a question using 'est-ce que':","template":"Est-{0} que tu parles français ?","gaps":[{"options":["ce","il","que","tu"],"answer":0}],"exp":"'Est-ce que' (literally 'is it that') is the standard question-forming phrase. It is written as three words: est-ce que. Note the hyphen in 'est-ce'.","lesson":"fr-clinic-order"},
  {"id":"fr-1357","topic":"fr-clinic-order","type":"typed","q":"Correct the adverb position: 'Je toujours mange ici.'","ans":"Je mange toujours ici.","alts":["je mange toujours ici","Je mange toujours ici"],"ignoreAccents":false,"exp":"'Toujours' (always) goes after the conjugated verb: Je mange toujours ici. Placing it between subject and verb is an English-style error.","lesson":"fr-clinic-order"},
  {"id":"fr-1358","topic":"fr-clinic-order","type":"mcq","q":"Which is the correct negative imperative?","opts":["Ne le prends pas.","Le ne prends pas.","Prends-le ne pas.","Ne prends pas le."],"ans":0,"exp":"In a negative imperative, the pronoun stays before the verb (unlike affirmative imperative where it goes after with a hyphen). 'Ne le prends pas' = Don't take it.","lesson":"fr-clinic-order"},
  {"id":"fr-1359","topic":"fr-clinic-order","type":"mcq","q":"In 'Je lui parle', what role does 'lui' play?","opts":["Direct object (him/her)","Indirect object (to him/to her)","Reflexive pronoun","Stressed pronoun"],"ans":1,"exp":"'Lui' here = indirect object (to him/to her). 'Parler à quelqu'un' → lui. 'Je le vois' = I see him (direct); 'Je lui parle' = I speak to him (indirect).","lesson":"fr-clinic-order"},
  {"id":"fr-1360","topic":"fr-clinic-order","type":"gapfill","q":"Imperative with two pronouns — choose the indirect object:","template":"Parle-{0}-en !","gaps":[{"options":["lui","le","la","y"],"answer":0}],"exp":"'Parle-lui-en !' = Speak to him/her about it! In affirmative imperative: direct (le/la/les) before indirect (lui/leur). 'En' always comes last.","lesson":"fr-clinic-order"},
  {"id":"fr-1361","topic":"fr-clinic-order","type":"typed","q":"Translate: 'She never eats fish.'","ans":"Elle ne mange jamais de poisson.","alts":["elle ne mange jamais de poisson","Elle ne mange jamais de poisson"],"ignoreAccents":false,"exp":"'Ne...jamais' = never. Word order: ne + verb + jamais. After negation, du poisson → de poisson. Two rules: word order and article change.","lesson":"fr-clinic-order"},
  {"id":"fr-1362","topic":"fr-clinic-order","type":"mcq","q":"Spot the word order error: 'Je ne vais nulle part jamais.'","opts":["'Nulle part' and 'jamais' can't both be used.","'Jamais' and 'nulle part' should be separate — prefer one at a time.","The standard order is: 'Je ne vais jamais nulle part'.","There is no error."],"ans":2,"exp":"When combining two negatives, standard word order places the shorter one first: je ne vais jamais nulle part. 'Nulle part jamais' is not standard.","lesson":"fr-clinic-order"},
  {"id":"fr-1363","topic":"fr-clinic-order","type":"mcq","q":"In a sentence like 'Je préfère ne pas y aller', where does 'ne pas' go?","opts":["Around the infinitive: Je ne préfère pas y aller","Before the infinitive as a unit: ne pas y aller","After the infinitive","Split: 'ne y aller pas'"],"ans":1,"exp":"When negating an infinitive, 'ne pas' stays together as a unit BEFORE the infinitive: préférer ne pas faire, éviter de ne pas..., Je préfère ne pas y aller.","lesson":"fr-clinic-order"},
  {"id":"fr-1364","topic":"fr-clinic-order","type":"gapfill","q":"'No longer' — choose the correct negative word:","template":"Il ne boit {0} de café. Il a arrêté la semaine dernière.","gaps":[{"options":["plus","jamais","pas","rien"],"answer":0}],"exp":"'Ne...plus' = no longer / not anymore. The context ('stopped last week') confirms plus. 'Ne...jamais' = never (wouldn't fit — he used to drink coffee).","lesson":"fr-clinic-order"},
  {"id":"fr-1365","topic":"fr-clinic-order","type":"typed","q":"Rewrite with correct formal negation: 'Je veux pas aller là-bas.'","ans":"Je ne veux pas aller là-bas.","alts":["je ne veux pas aller là-bas","Je ne veux pas aller la-bas."],"ignoreAccents":true,"exp":"Add 'ne' before the conjugated verb: 'Je ne veux pas aller là-bas.' Without 'ne' is very informal speech; in writing it must be included.","lesson":"fr-clinic-order"},
  {"id":"fr-1366","topic":"fr-clinic-order","type":"mcq","q":"Which is the correct inversion question form?","opts":["Il vient-il ?","Vient il ?","Vient-il ?","Il-vient ?"],"ans":2,"exp":"Inversion requires a hyphen between verb and pronoun: Vient-il ? (Does he come?). No space, no extra pronoun before the verb. 'Il vient-il' is doubled — wrong.","lesson":"fr-clinic-order"},
  {"id":"fr-1367","topic":"fr-clinic-order","type":"mcq","q":"Where does 'déjà' go in 'I have already eaten'?","opts":["J'ai mangé déjà.","J'ai déjà mangé.","Déjà j'ai mangé.","J'ai mangé, déjà."],"ans":1,"exp":"In compound tenses, short adverbs (déjà, bien, souvent, toujours) go between the auxiliary and the past participle: J'ai déjà mangé.","lesson":"fr-clinic-order"},
  {"id":"fr-1368","topic":"fr-clinic-order","type":"gapfill","q":"Negative imperative for 'tu' with an -er verb:","template":"Ne {0} pas ici !","gaps":[{"options":["mange","manges","manger","mangez"],"answer":0}],"exp":"Negative imperative for 'tu' uses the verb form WITHOUT the -s: 'Ne mange pas !' (not 'Ne manges pas'). This -er verb tu form loses its -s in negative imperative.","lesson":"fr-clinic-order"},
  {"id":"fr-1369","topic":"fr-clinic-order","type":"typed","q":"Translate: 'He doesn't speak French anymore.'","ans":"Il ne parle plus français.","alts":["il ne parle plus français","Il ne parle plus le français.","il ne parle plus le français"],"ignoreAccents":true,"exp":"'Ne...plus' = no longer/anymore. Word order: ne + parle + plus. After negation with plus: no article before 'français' (language after parler without article).","lesson":"fr-clinic-order"},
  {"id":"fr-1370","topic":"fr-clinic-order","type":"mcq","q":"Spot the error: 'Tu peux pas venir ?' in formal writing.","opts":["This is correct — informal register.","The 'ne' is missing: 'Tu ne peux pas venir ?'","'Pas' should be 'rien'.","The question mark is misplaced."],"ans":1,"exp":"In formal/written French, 'ne' must be present: 'Tu ne peux pas venir ?' Dropping 'ne' is a hallmark of informal speech.","lesson":"fr-clinic-order"},
  {"id":"fr-1371","topic":"fr-clinic-order","type":"mcq","q":"How do you say 'I see him' using an object pronoun?","opts":["Je vois lui.","Je lui vois.","Je le vois.","Le je vois."],"ans":2,"exp":"Direct object pronouns go before the conjugated verb in statements: Je le vois. 'Je vois lui' is wrong — 'lui' after the verb is a stressed pronoun used for emphasis, not as a direct object.","lesson":"fr-clinic-order"},
  {"id":"fr-1372","topic":"fr-clinic-order","type":"gapfill","q":"Choose the correct negation for 'no longer' with context:","template":"Elle ne dort {0} bien depuis l'accident.","gaps":[{"options":["plus","jamais","encore","rien"],"answer":0}],"exp":"'Ne...plus' = no longer/anymore. Since the accident she no longer sleeps well. 'Ne...jamais' = never (but she used to sleep well). 'Ne...encore' would need 'pas encore' = not yet.","lesson":"fr-clinic-order"},
  {"id":"fr-1373","topic":"fr-clinic-order","type":"typed","q":"Correct: 'Je ne veux rien savoir pas.'","ans":"Je ne veux rien savoir.","alts":["je ne veux rien savoir","Je ne veux rien savoir"],"ignoreAccents":false,"exp":"'Ne...rien' is already a complete negation — don't add 'pas' as well. 'Je ne veux rien savoir' = I don't want to know anything. Double negation like this is an English-transfer error.","lesson":"fr-clinic-order"},
  {"id":"fr-1374","topic":"fr-clinic-order","type":"mcq","q":"What does 'y' refer to in 'Il y en a beaucoup' ?","opts":["A specific person","A place or situation already mentioned","The subject 'il'","Nothing — 'y' is just a filler here"],"ans":1,"exp":"'Y' replaces a location or context (à + place/thing): Il y a beaucoup de monde ici → Il y en a beaucoup. 'En' replaces de + noun. Together they produce the idiomatic 'il y en a'.","lesson":"fr-clinic-order"},

  // ── fr-clinic-verbs (fr-1375–fr-1404) ───────────────────────────────────
  {"id":"fr-1375","topic":"fr-clinic-verbs","type":"mcq","q":"Which is the correct 'nous' form of 'parler'?","opts":["nous parle","nous parlons","nous parlez","nous parlent"],"ans":1,"exp":"'Nous parlons' — the -ons ending for nous is identical for all regular -er verbs. Don't confuse: vous parlez (-ez), ils parlent (-ent).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1376","topic":"fr-clinic-verbs","type":"typed","q":"Correct the conjugation error: 'Vous mangez du pain, mais ils mange de la salade.'","ans":"Vous mangez du pain, mais ils mangent de la salade.","alts":["vous mangez du pain, mais ils mangent de la salade","Vous mangez du pain, mais ils mangent de la salade"],"ignoreAccents":false,"exp":"Ils/elles + -er verb → -ent: ils mangent. Very common error: forgetting the -ent ending for third-person plural. The ending is silent but essential in writing.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1377","topic":"fr-clinic-verbs","type":"mcq","q":"Which sentence has a conjugation error?","opts":["Elle finit ses devoirs.","Tu finis tard.","Nous finissons ensemble.","Ils finit bien."],"ans":3,"exp":"'Ils finit' is wrong — third-person plural of 'finir' is 'ils finissent'. 'Finit' is the third-person SINGULAR form.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1378","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct form of 'aller':","template":"Je {0} au supermarché tous les samedis.","gaps":[{"options":["vais","va","allons","aller"],"answer":0}],"exp":"'Aller' is fully irregular: je vais / tu vas / il-elle va / nous allons / vous allez / ils-elles vont. 'Je vais' = I go.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1379","topic":"fr-clinic-verbs","type":"typed","q":"Translate: 'They (masculine) take the bus.'","ans":"Ils prennent le bus.","alts":["ils prennent le bus","Ils prennent le bus"],"ignoreAccents":false,"exp":"'Prendre' is irregular: je prends / tu prends / il prend / nous prenons / vous prenez / ils prennent. Note the double -nn- in the plural forms.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1380","topic":"fr-clinic-verbs","type":"mcq","q":"Which verb form is correct for 'tu' with a regular -er verb?","opts":["tu mange","tu manges","tu mangent","tu mangez"],"ans":1,"exp":"Tu + -er verb → -es: tu manges. The -s is silent but mandatory in writing. Very common error: 'tu mange' (missing the -s).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1381","topic":"fr-clinic-verbs","type":"mcq","q":"Spot the error: 'Il saits conduire.'","opts":["'Saits' is wrong — the correct form is 'sait' (no added -t or -s for il/elle).","This is correct.","'Conduire' should be 'conduisant'.","'Il' should be 'elle'."],"ans":0,"exp":"'Savoir' conjugated: je sais / tu sais / il sait. Il/elle form doesn't add extra letters — 'saits' does not exist. The -t in 'sait' is already the ending.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1382","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct 'nous' form of 'apprendre':","template":"Nous {0} le français ensemble.","gaps":[{"options":["apprenons","apprennent","apprenez","apprend"],"answer":0}],"exp":"'Apprendre': je apprends → j'apprends / nous apprenons (no double -nn- in the nous form). Plural double-nn only in ils/elles: ils apprennent.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1383","topic":"fr-clinic-verbs","type":"typed","q":"Correct the conjugation: 'Elle vas à l'école.'","ans":"Elle va à l'école.","alts":["elle va à l'école","elle va à l'ecole."],"ignoreAccents":true,"exp":"'Aller': il/elle va (not 'vas'). 'Vas' is only for 'tu': tu vas. Common error: using the 'tu' form for 'il/elle'.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1384","topic":"fr-clinic-verbs","type":"mcq","q":"What is 'avoir' for 'ils/elles'?","opts":["ils avons","ils ont","ils avez","ils avaient"],"ans":1,"exp":"'Avoir': je suis → wait, avoir: j'ai / tu as / il-elle a / nous avons / vous avez / ils-elles ont. 'Ils ont' = they have.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1385","topic":"fr-clinic-verbs","type":"mcq","q":"Which is a stem-changing verb?","opts":["parler","finir","appeler","vendre"],"ans":2,"exp":"'Appeler' is stem-changing: j'appelle (double -ll-) / tu appelles / il appelle / nous appelons (no change) / vous appelez / ils appellent. The doubling occurs to preserve the /ɛl/ sound.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1386","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct form of 'être':","template":"Elle {0} très fatiguée aujourd'hui.","gaps":[{"options":["est","a","es","ont"],"answer":0}],"exp":"'Être': je suis / tu es / il-elle est / nous sommes / vous êtes / ils-elles sont. 'Elle est' = she is. 'Elle a' = she has (différent verb).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1387","topic":"fr-clinic-verbs","type":"typed","q":"Translate: 'We make mistakes.'","ans":"Nous faisons des erreurs.","alts":["nous faisons des erreurs","Nous faisons des erreurs"],"ignoreAccents":false,"exp":"'Faire': nous faisons (irregular — note 'fais-' stem with -ons). 'Faire une erreur' = to make a mistake. 'Faisont' does not exist.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1388","topic":"fr-clinic-verbs","type":"mcq","q":"Spot the error: 'Il faisent du sport chaque jour.'","opts":["'Faisent' is wrong — 'ils font' is the correct plural of 'faire'.","'Sport' should be 'le sport'.","'Chaque jour' should be 'tous les jours'.","There is no error."],"ans":0,"exp":"'Faire' is irregular: ils FONT (not faisent — that form doesn't exist). Common error: applying a regular pattern to an irregular verb.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1389","topic":"fr-clinic-verbs","type":"mcq","q":"What is the correct form of 'vouloir' for 'vous'?","opts":["vous voulez","vous voulons","vous veulent","vous voulaient"],"ans":0,"exp":"'Vouloir': je veux / tu veux / il veut / nous voulons / vous voulez / ils veulent. 'Vous voulez' = you want. Note the stem change: veu- (singular) / voul- (nous/vous).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1390","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct 'tu' form of 'partir':","template":"Tu {0} à quelle heure demain ?","gaps":[{"options":["pars","pares","partez","partir"],"answer":0}],"exp":"'Partir': je pars / tu pars / il part / nous partons / vous partez / ils partent. Short -ir verbs (partir, sortir, dormir) have no -iss- infix unlike finir.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1391","topic":"fr-clinic-verbs","type":"typed","q":"Correct: 'Il faisent la cuisine tous les soirs.'","ans":"Ils font la cuisine tous les soirs.","alts":["ils font la cuisine tous les soirs","Ils font la cuisine tous les soirs"],"ignoreAccents":false,"exp":"'Faire' irregular plural: ils font. 'Faisent' does not exist — never add -ent to the 'fai-' stem. Also note: 'il' becomes 'ils' if plural is intended.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1392","topic":"fr-clinic-verbs","type":"mcq","q":"What is the correct 'nous' form of 'être'?","opts":["nous êtes","nous sommes","nous sont","nous avons"],"ans":1,"exp":"'Être': nous sommes. Fully irregular. The other forms: je suis / tu es / il est / vous êtes / ils sont. 'Nous êtes' confuses nous and vous.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1393","topic":"fr-clinic-verbs","type":"mcq","q":"Which conjugation is wrong?","opts":["je bois","tu bois","elle boit","nous boivons"],"ans":3,"exp":"'Boire': nous buvons (not boivons). Irregular stem: boi- (singular + ils) / buv- (nous + vous): je bois / tu bois / il boit / nous buvons / vous buvez / ils boivent.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1394","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct 'vous' form of 'aller':","template":"Vous {0} où ce soir ?","gaps":[{"options":["allez","allons","vont","aller"],"answer":0}],"exp":"'Aller': vous allez. Remember: nous allons / vous allez / ils vont. Common mix-up: confusing 'nous allons' with 'vous allons'.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1395","topic":"fr-clinic-verbs","type":"typed","q":"Translate formally: 'Do you have the time?' (vous)","ans":"Avez-vous l'heure ?","alts":["avez-vous l'heure","Vous avez l'heure ?","vous avez l'heure ?","Est-ce que vous avez l'heure ?","est-ce que vous avez l'heure ?"],"ignoreAccents":true,"exp":"'Avez-vous l'heure ?' uses inversion (formal). 'Vous avez l'heure ?' (rising intonation) is semi-formal. Both are correct — inversion is more formal.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1396","topic":"fr-clinic-verbs","type":"mcq","q":"Which verb follows a different conjugation pattern from the others?","opts":["chanter","danser","prendre","parler"],"ans":2,"exp":"'Prendre' is an irregular -re verb with a unique pattern. The others (chanter, danser, parler) are regular -er verbs with identical endings.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1397","topic":"fr-clinic-verbs","type":"mcq","q":"Spot the error: 'Nous devez partir maintenant.'","opts":["'Devez' should be 'devons' — first-person plural uses -ons.","This is correct.","'Partir' should be 'partez'.","'Maintenant' should be at the start."],"ans":0,"exp":"'Nous devons' — first-person plural of 'devoir'. 'Devez' is the vous form. Mixing up nous/vous endings is one of the most common learner errors.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1398","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct form of 'boire':","template":"Il {0} beaucoup de café.","gaps":[{"options":["boit","boivent","buvez","bu"],"answer":0}],"exp":"'Boire': il/elle boit. 'Boivent' is ils/elles form. 'Buvez' is vous form. 'Bu' is the past participle.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1399","topic":"fr-clinic-verbs","type":"typed","q":"Correct: 'Elle comprend bien mais son frère comprenent pas.'","ans":"Elle comprend bien mais son frère ne comprend pas.","alts":["elle comprend bien mais son frère ne comprend pas","Elle comprend bien mais son frere ne comprend pas."],"ignoreAccents":true,"exp":"'Son frère' is singular → comprend (not comprenent). Also 'ne' is missing. Two errors: wrong number agreement on the verb, and missing 'ne'.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1400","topic":"fr-clinic-verbs","type":"mcq","q":"What is 'vendre' conjugated as for 'il'?","opts":["il vendre","il vendt","il vend","il vends"],"ans":2,"exp":"Regular -re verbs: drop -re, and the stem already ends in -d, so no extra letter is added: il vend. Don't add -t (il vendt) or -s (il vends).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1401","topic":"fr-clinic-verbs","type":"mcq","q":"Which is the correct first-person singular of 'pouvoir'?","opts":["je peux","je peut","je pouvons","je pouviez"],"ans":0,"exp":"'Pouvoir': je peux / tu peux / il peut / nous pouvons / vous pouvez / ils peuvent. 'Je peux' is an irregular form — note the -x ending (like je veux for vouloir).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1402","topic":"fr-clinic-verbs","type":"gapfill","q":"Choose the correct 'elles' form of 'connaître':","template":"Elles {0} bien la danse classique.","gaps":[{"options":["connaissent","connais","connaissons","connaissez"],"answer":0}],"exp":"'Connaître': je connais / tu connais / il connaît / nous connaissons / vous connaissez / ils-elles connaissent. The circumflex on the 'î' in 'connaît' is a spelling rule.","lesson":"fr-clinic-verbs"},
  {"id":"fr-1403","topic":"fr-clinic-verbs","type":"typed","q":"Translate: 'He knows how to swim.'","ans":"Il sait nager.","alts":["il sait nager","Il sait nager"],"ignoreAccents":false,"exp":"'Savoir + infinitive' = to know how to do something. 'Savoir' is irregular: il sait. Don't confuse with 'connaître' (to be familiar with people/places).","lesson":"fr-clinic-verbs"},
  {"id":"fr-1404","topic":"fr-clinic-verbs","type":"mcq","q":"What is 'finir' conjugated as for 'vous'?","opts":["vous finissez","vous finissons","vous finir","vous finiez"],"ans":0,"exp":"Regular -ir verbs (finir type): vous finissez. The -iss- infix appears in all plural forms and vous: nous finissons / vous finissez / ils finissent.","lesson":"fr-clinic-verbs"},

  // ── fr-clinic-accents (fr-1405–fr-1434) ─────────────────────────────────
  {"id":"fr-1405","topic":"fr-clinic-accents","type":"mcq","q":"Which word is spelled correctly?","opts":["cafe","café","cafee","caffé"],"ans":1,"exp":"'Café' always has an accent aigu on the 'e'. Without the accent, 'cafe' looks English. The accent changes the vowel sound: /e/ (closed) instead of a neutral vowel.","lesson":"fr-clinic-accents"},
  {"id":"fr-1406","topic":"fr-clinic-accents","type":"typed","q":"Correct the spelling: 'Je suis etudiant.'","ans":"Je suis étudiant.","alts":["je suis étudiant","Je suis etudiant."],"ignoreAccents":false,"exp":"'Étudiant' must have an accent aigu on the first 'é'. Forgetting accents is one of the most common written errors. Accents are part of correct French spelling.","lesson":"fr-clinic-accents"},
  {"id":"fr-1407","topic":"fr-clinic-accents","type":"mcq","q":"What sound does 'ç' (cédille) produce?","opts":["k sound (as in 'car')","s sound (as in 'see')","sh sound (as in 'shoe')","z sound (as in 'zero')"],"ans":1,"exp":"The cédille turns 'c' into an /s/ sound before a, o, or u: garçon, leçon, français. Without cédille, 'c' before a/o/u makes a /k/ sound.","lesson":"fr-clinic-accents"},
  {"id":"fr-1408","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly spelled nationality:","template":"Il est {0}.","gaps":[{"options":["français","francais","françaiz","francaiz"],"answer":0}],"exp":"'Français' needs both the cédille (ç) and the accent — actually just the cédille: garçon, français, leçon. 'Francais' is a very common error.","lesson":"fr-clinic-accents"},
  {"id":"fr-1409","topic":"fr-clinic-accents","type":"typed","q":"Correct the accent error: 'ou vas-tu ?' (where are you going?)","ans":"où vas-tu ?","alts":["Où vas-tu ?","où vas-tu","Où vas-tu"],"ignoreAccents":false,"exp":"'Où' (where) has a grave accent to distinguish it from 'ou' (or). This is one of several accent pairs that change meaning: à/a, là/la, sûr/sur.","lesson":"fr-clinic-accents"},
  {"id":"fr-1410","topic":"fr-clinic-accents","type":"mcq","q":"What is the difference between 'ou' and 'où'?","opts":["No difference — they are spelled the same.","'Ou' (no accent) means 'or'; 'où' (grave accent) means 'where'.","'Ou' means 'where'; 'où' means 'or'.","'Où' is only used in indirect questions."],"ans":1,"exp":"'Ou' = or (Il est grand ou petit ?). 'Où' = where (Où habites-tu ?). The grave accent is the only visual difference — it completely changes the meaning.","lesson":"fr-clinic-accents"},
  {"id":"fr-1411","topic":"fr-clinic-accents","type":"mcq","q":"Which word needs a cédille?","opts":["cinema","garcon","cafe","Europe"],"ans":1,"exp":"'Garçon' needs a cédille to make 'ç' sound like /s/. Without it, 'garcon' would be pronounced with a /k/ sound before 'o'.","lesson":"fr-clinic-accents"},
  {"id":"fr-1412","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly spelled form:","template":"Je {0} le thé au café.","gaps":[{"options":["préfère","prefere","prefer","prefère"],"answer":0}],"exp":"'Préfère' has an accent aigu on the first 'é' and a grave accent on the second 'è'. 'Prefere' has no accents — wrong. 'Prefer' is English.","lesson":"fr-clinic-accents"},
  {"id":"fr-1413","topic":"fr-clinic-accents","type":"typed","q":"Add all missing accents: 'Les eleves sont arrives a l'ecole.'","ans":"Les élèves sont arrivés à l'école.","alts":["les élèves sont arrivés à l'école","Les élèves sont arrivés à l'école"],"ignoreAccents":false,"exp":"Missing accents: élèves (é+è), arrivés (é), à (grave), école (é). Accents are required in formal writing and affect pronunciation.","lesson":"fr-clinic-accents"},
  {"id":"fr-1414","topic":"fr-clinic-accents","type":"mcq","q":"What does the tréma (ë, ï, ü) indicate?","opts":["The vowel is silent.","The vowel is more stressed.","The vowel is pronounced separately from the vowel before it.","The letter has a cedilla sound."],"ans":2,"exp":"Tréma = diaeresis: each vowel is pronounced separately. Naïf /na.if/ not /nɛf/. Noël /nɔ.ɛl/ not /nœl/. It prevents the two vowels from forming a single sound.","lesson":"fr-clinic-accents"},
  {"id":"fr-1415","topic":"fr-clinic-accents","type":"mcq","q":"Which word has a tréma?","opts":["être","élève","naïf","façon"],"ans":2,"exp":"'Naïf' has a tréma on the 'ï': pronounced /na.if/. Other tréma words: Noël, Noëlle, coïncidence, ambiguë. 'Être' has circumflex, 'élève' has aigu+grave, 'façon' has cédille.","lesson":"fr-clinic-accents"},
  {"id":"fr-1416","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly spelled past participle:","template":"Elle est {0} en France.","gaps":[{"options":["née","nee","néee","nèe"],"answer":0}],"exp":"'Née' = born (feminine past participle of naître). The accent aigu on 'é' is required. 'Nee' without accent is wrong.","lesson":"fr-clinic-accents"},
  {"id":"fr-1417","topic":"fr-clinic-accents","type":"typed","q":"Add the missing accent: 'tres bien'","ans":"très bien","alts":["Très bien","Très Bien"],"ignoreAccents":false,"exp":"'Très' (very) has an accent grave on the 'è'. A very common omission. Other grave-accent words: père, mère, frère, après, problème.","lesson":"fr-clinic-accents"},
  {"id":"fr-1418","topic":"fr-clinic-accents","type":"mcq","q":"What accent is on the 'e' in 'problème'?","opts":["Accent aigu (é)","Accent grave (è)","Accent circonflexe (ê)","No accent"],"ans":1,"exp":"'Problème' ends in 'è' — accent grave. The grave accent signals an open /ɛ/ sound (like 'e' in 'bed'). Contrast: café (é = closed /e/, like 'ay').","lesson":"fr-clinic-accents"},
  {"id":"fr-1419","topic":"fr-clinic-accents","type":"mcq","q":"Which is the correct spelling?","opts":["une ecole","une école","une écôle","une eecole"],"ans":1,"exp":"'École' has an accent aigu: é. The circumflex on 'ô' would be wrong here — école has no circumflex. Many school-related words start with é-: étudiant, élève, école.","lesson":"fr-clinic-accents"},
  {"id":"fr-1420","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correct spelling:","template":"Je suis triste — j'ai raté l'examen. Je suis {0}.","gaps":[{"options":["bête","bete","bette","béte"],"answer":0}],"exp":"'Bête' (stupid/silly) has an accent circonflexe on 'ê'. 'Bete' without accent is wrong. 'Bette' is a different word (Swiss chard).","lesson":"fr-clinic-accents"},
  {"id":"fr-1421","topic":"fr-clinic-accents","type":"typed","q":"Write this farewell correctly: 'a bientot'","ans":"à bientôt","alts":["À bientôt","a bientôt","à bientot"],"ignoreAccents":false,"exp":"'À bientôt' needs two accents: grave accent on 'à' (preposition, not 'a' = has) and circonflexe on 'ô' in 'bientôt'.","lesson":"fr-clinic-accents"},
  {"id":"fr-1422","topic":"fr-clinic-accents","type":"mcq","q":"Which sentence has a spelling error?","opts":["C'est une bête question.","Je bois du thé.","Elle habite à Paris.","Il mange du gateau."],"ans":3,"exp":"'Gâteau' needs an accent circonflexe on 'â': gâteau. 'Gateau' without accent is a very common written error.","lesson":"fr-clinic-accents"},
  {"id":"fr-1423","topic":"fr-clinic-accents","type":"mcq","q":"What does the accent circonflexe (^) often mark historically?","opts":["A silent vowel at the end","A place where an 's' existed in Old French or Latin","A borrowed word","A nasal vowel"],"ans":1,"exp":"The circumflex often marks a historical 's': hôpital (hospital), forêt (forest), fête (feast), île (isle). This is why English cognates often have 's' where French has '^'.","lesson":"fr-clinic-accents"},
  {"id":"fr-1424","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly spelled word:","template":"Tu aimes le {0} ?","gaps":[{"options":["théâtre","theatre","théatre","théattre"],"answer":0}],"exp":"'Théâtre' has both an accent aigu on 'é' and a circumflex on 'â'. Both accents are required. 'Theatre' (no accents) is the English spelling.","lesson":"fr-clinic-accents"},
  {"id":"fr-1425","topic":"fr-clinic-accents","type":"typed","q":"Correct the spelling: 'c'est une fete magnifique'","ans":"C'est une fête magnifique.","alts":["C'est une fête magnifique","c'est une fête magnifique"],"ignoreAccents":false,"exp":"'Fête' (party/feast) needs an accent circonflexe on 'ê'. Also capitalise the start. The historical 's' in 'feste' → fête (with circumflex).","lesson":"fr-clinic-accents"},
  {"id":"fr-1426","topic":"fr-clinic-accents","type":"mcq","q":"Which word uses an accent aigu (é)?","opts":["père","tête","été","crème"],"ans":2,"exp":"'Été' (summer / past participle of être) has é — accent aigu. 'Père' and 'crème' have è (grave). 'Tête' has ê (circumflex).","lesson":"fr-clinic-accents"},
  {"id":"fr-1427","topic":"fr-clinic-accents","type":"mcq","q":"Why does 'hôtel' have a circumflex?","opts":["To show it is a luxury building.","To indicate the 'h' is aspirate.","It marks a historical 's': hostel → hôtel.","All words ending in -el have a circumflex."],"ans":2,"exp":"The circumflex in hôtel replaces a historical 's': Old French 'hostel'. Same pattern: hôpital (hospital), forêt (forest), île (isle), fête (feast/festival).","lesson":"fr-clinic-accents"},
  {"id":"fr-1428","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly accented word for 'father':","template":"Mon {0} est avocat.","gaps":[{"options":["père","pere","pêre","pére"],"answer":0}],"exp":"'Père' (father) has an accent grave on 'è'. 'Pêre' (circumflex) and 'pére' (aigu) do not exist. Other grave-e family words: mère, frère.","lesson":"fr-clinic-accents"},
  {"id":"fr-1429","topic":"fr-clinic-accents","type":"typed","q":"Write correctly: 'la creme brulee'","ans":"la crème brûlée","alts":["La crème brûlée","la creme brûlée"],"ignoreAccents":false,"exp":"'Crème' has a grave accent (è); 'brûlée' has a circumflex on 'û' and an acute accent on the final 'é'. Three accents in two words!","lesson":"fr-clinic-accents"},
  {"id":"fr-1430","topic":"fr-clinic-accents","type":"mcq","q":"Which word has NO accent mark?","opts":["élève","hôpital","café","route"],"ans":3,"exp":"'Route' (road) has no accent. 'Élève' has é+è, 'hôpital' has ô, 'café' has é. Not all French words need accents.","lesson":"fr-clinic-accents"},
  {"id":"fr-1431","topic":"fr-clinic-accents","type":"mcq","q":"Which is the traditional correct spelling of 'please'?","opts":["sil vous plait","s'il vous plait","s'il vous plaît","s'il-vous-plaît"],"ans":2,"exp":"Traditional spelling: 's'il vous plaît' with a circumflex on 'î'. Modern orthographic reforms allow 'plait' without circumflex, but the traditional form is safer in exams.","lesson":"fr-clinic-accents"},
  {"id":"fr-1432","topic":"fr-clinic-accents","type":"gapfill","q":"Choose the correctly spelled word:","template":"J'ai une {0} !","gaps":[{"options":["idée","idee","idéé","ídée"],"answer":0}],"exp":"'Idée' (idea) has two accent aigus: idée. Both 'e's need the accent. 'Idee' without accents is wrong.","lesson":"fr-clinic-accents"},
  {"id":"fr-1433","topic":"fr-clinic-accents","type":"typed","q":"Correct: 'C'est une regle importante.'","ans":"C'est une règle importante.","alts":["c'est une règle importante","C'est une règle importante"],"ignoreAccents":false,"exp":"'Règle' (rule) has an accent grave on 'è'. A very common omission in student writing.","lesson":"fr-clinic-accents"},
  {"id":"fr-1434","topic":"fr-clinic-accents","type":"mcq","q":"Which is the correct spelling of 'already' in French?","opts":["deja","déja","déjà","dejà"],"ans":2,"exp":"'Déjà' needs two accents: accent aigu on 'é' and accent grave on 'à'. Both are required. 'Deja' (no accents) is a very common error.","lesson":"fr-clinic-accents"},

  // ── fr-clinic-register (fr-1435–fr-1464) ────────────────────────────────
  {"id":"fr-1435","topic":"fr-clinic-register","type":"mcq","q":"Which situation calls for 'vous' rather than 'tu'?","opts":["Talking to your younger sibling","Addressing a new colleague you've just met in a professional context","Texting your best friend","Speaking to a classmate you know well"],"ans":1,"exp":"'Vous' is used for formal situations, strangers, older people, and professional contexts. 'Tu' is for friends, family, children, and peers you know well.","lesson":"fr-clinic-register"},
  {"id":"fr-1436","topic":"fr-clinic-register","type":"typed","q":"Make this informal question formal: 'T'as l'heure ?'","ans":"Avez-vous l'heure ?","alts":["avez-vous l'heure","Pourriez-vous me dire l'heure ?","pourriez-vous me dire l'heure ?","Auriez-vous l'heure ?"],"ignoreAccents":true,"exp":"'T'as' is very informal ('tu as' contracted). Formal: 'Avez-vous l'heure ?' or even more polite: 'Pourriez-vous me dire l'heure ?'","lesson":"fr-clinic-register"},
  {"id":"fr-1437","topic":"fr-clinic-register","type":"mcq","q":"Which greeting is most appropriate to start a formal email?","opts":["Salut !","Yo !","Madame, Monsieur,","Coucou !"],"ans":2,"exp":"'Madame, Monsieur,' or 'Madame,' / 'Monsieur,' are standard formal email openings. 'Salut', 'Coucou', 'Yo' are all informal/slang and completely inappropriate in formal writing.","lesson":"fr-clinic-register"},
  {"id":"fr-1438","topic":"fr-clinic-register","type":"gapfill","q":"Choose the polite verb form for a reservation:","template":"Je {0} réserver une table pour deux personnes.","gaps":[{"options":["voudrais","veux","voulais","voudrez"],"answer":0}],"exp":"'Je voudrais' (conditional of vouloir) is the polite way to make a request. 'Je veux' (present) sounds demanding. Always prefer conditional in formal/service contexts.","lesson":"fr-clinic-register"},
  {"id":"fr-1439","topic":"fr-clinic-register","type":"typed","q":"Make this more formal: 'T'as pas un stylo ?'","ans":"Avez-vous un stylo ?","alts":["avez-vous un stylo","Auriez-vous un stylo ?","auriez-vous un stylo ?","Auriez-vous un stylo"],"ignoreAccents":true,"exp":"'T'as pas' = very informal (dropping ne, contracting tu as). Formal: 'Avez-vous un stylo ?' or 'Pourriez-vous me prêter un stylo ?'","lesson":"fr-clinic-register"},
  {"id":"fr-1440","topic":"fr-clinic-register","type":"mcq","q":"Why might 'Je veux une baguette' be considered rude in a bakery?","opts":["'Baguette' is an informal word.","It sounds like a direct demand — 'Je voudrais' is more polite.","'Une' should be 'la'.","This is perfectly polite."],"ans":1,"exp":"'Je veux' = I want (blunt demand). In French service contexts, 'Je voudrais' (I would like) or 'Pourriez-vous me donner' is expected. Directness can come across as rude.","lesson":"fr-clinic-register"},
  {"id":"fr-1441","topic":"fr-clinic-register","type":"mcq","q":"'Je parle pas anglais' is an example of what?","opts":["Formal written French","Spoken informal French (dropping 'ne')","A grammar error that always needs correcting","The subjunctive mood"],"ans":1,"exp":"Dropping 'ne' in negation is a hallmark of informal spoken French. 'Je ne parle pas anglais' is the correct formal form. Both are used, but register matters.","lesson":"fr-clinic-register"},
  {"id":"fr-1442","topic":"fr-clinic-register","type":"gapfill","q":"Choose the correct infinitive for a formal request:","template":"Veuillez {0} ce formulaire.","gaps":[{"options":["remplir","remplissez","remplis","remplissant"],"answer":0}],"exp":"'Veuillez + infinitive' = formal polite request (please + infinitive). 'Veuillez remplir' = Please fill in. Other examples: Veuillez patienter, Veuillez trouver ci-joint.","lesson":"fr-clinic-register"},
  {"id":"fr-1443","topic":"fr-clinic-register","type":"typed","q":"Change to informal register: 'Comment allez-vous ?'","ans":"Ça va ?","alts":["Ca va ?","Comment tu vas ?","comment tu vas ?","Tu vas bien ?","tu vas bien ?"],"ignoreAccents":true,"exp":"'Comment allez-vous ?' is formal (vous + inversion). Informal alternatives: 'Ça va ?' / 'Comment tu vas ?' / 'Tu vas bien ?' — all using 'tu' and simpler structure.","lesson":"fr-clinic-register"},
  {"id":"fr-1444","topic":"fr-clinic-register","type":"mcq","q":"Which word is informal/argot for 'voiture' (car)?","opts":["automobile","bagnole","véhicule","carrosse"],"ans":1,"exp":"'Bagnole' = informal slang for 'voiture'. 'Automobile' and 'véhicule' are formal/technical. 'Carrosse' = carriage (horse-drawn, archaic).","lesson":"fr-clinic-register"},
  {"id":"fr-1445","topic":"fr-clinic-register","type":"mcq","q":"Spot the register error in a formal letter: 'Salut, je veux vous informer de ma démission.'","opts":["'Vous informer' is too formal.","'Salut' is inappropriate — a formal letter must begin with 'Monsieur/Madame'.","'Démission' should be 'départ'.","There is no register error."],"ans":1,"exp":"'Salut' is casual/informal and completely inappropriate in a formal letter. A formal letter opens with 'Monsieur,' 'Madame,' or 'Madame, Monsieur,'.","lesson":"fr-clinic-register"},
  {"id":"fr-1446","topic":"fr-clinic-register","type":"gapfill","q":"Choose the most formal adjective for a polite introduction:","template":"Je suis {0} de faire votre connaissance.","gaps":[{"options":["ravi","super content","trop bien","cool"],"answer":0}],"exp":"'Ravi(e) de faire votre connaissance' = delighted to make your acquaintance (formal). 'Super content', 'trop bien', 'cool' are all informal/argot — avoid in professional contexts.","lesson":"fr-clinic-register"},
  {"id":"fr-1447","topic":"fr-clinic-register","type":"typed","q":"Rewrite formally: 'C'est pas grave, t'inquiète.'","ans":"Ce n'est pas grave, ne vous inquiétez pas.","alts":["ce n'est pas grave, ne vous inquiétez pas","Ce n'est pas grave, ne vous inquiétez pas"],"ignoreAccents":true,"exp":"Two informal features: dropped 'ne' (c'est pas) and contracted 't'inquiète' (te as tu). Formal: 'Ce n'est pas grave, ne vous inquiétez pas.'","lesson":"fr-clinic-register"},
  {"id":"fr-1448","topic":"fr-clinic-register","type":"mcq","q":"Which is the correct formal way to close a French letter?","opts":["Bisous !","À plus !","Veuillez agréer l'expression de mes salutations distinguées.","Ciao !"],"ans":2,"exp":"'Veuillez agréer l'expression de mes salutations distinguées' is the traditional formal closing. 'Bisous' and 'Ciao' are very informal. 'À plus' is informal shorthand for 'à plus tard'.","lesson":"fr-clinic-register"},
  {"id":"fr-1449","topic":"fr-clinic-register","type":"mcq","q":"What is the informal equivalent of 'travailler' (to work)?","opts":["bosser","boulot","bossage","travaille"],"ans":0,"exp":"'Bosser' = informal verb for 'travailler'. 'Boulot' = informal noun for 'travail' (job/work). 'Bossage' and 'travaille' are not the right answer here.","lesson":"fr-clinic-register"},
  {"id":"fr-1450","topic":"fr-clinic-register","type":"gapfill","q":"Choose the correct polite request form:","template":"Pourriez-{0} m'aider, s'il vous plaît ?","gaps":[{"options":["vous","tu","on","nous"],"answer":0}],"exp":"'Pourriez-vous' = Could you (conditional of pouvoir + inversion). This is a polite, formal way to ask for help. 'Pourriez-tu' doesn't exist — conditional + inversion always uses vous for formal requests.","lesson":"fr-clinic-register"},
  {"id":"fr-1451","topic":"fr-clinic-register","type":"typed","q":"Translate formally: 'I would like to speak to the manager.'","ans":"Je voudrais parler au directeur.","alts":["je voudrais parler au directeur","Je voudrais parler au responsable.","je voudrais parler au responsable","Je voudrais parler à un responsable."],"ignoreAccents":true,"exp":"'Je voudrais' (conditional = polite) + 'parler au directeur/responsable'. 'Je veux parler' would sound too blunt in a formal context.","lesson":"fr-clinic-register"},
  {"id":"fr-1452","topic":"fr-clinic-register","type":"mcq","q":"Which expression is formal?","opts":["T'as qu'à faire ça.","Je vous prie de bien vouloir trouver ci-joint...","C'est chiant.","Laisse tomber."],"ans":1,"exp":"'Je vous prie de bien vouloir...' is classic formal written French. The others are informal/slang: 't'as qu'à' = you just have to (very casual), 'chiant' = annoying (vulgar), 'laisse tomber' = forget it (casual).","lesson":"fr-clinic-register"},
  {"id":"fr-1453","topic":"fr-clinic-register","type":"mcq","q":"When is it acceptable to use 'tu' with someone you don't know well?","opts":["Never — always use 'vous' with strangers.","In casual social settings with peers of similar age, especially if they use 'tu' first.","Always in professional emails to seem friendly.","When speaking to shop assistants who are older than you."],"ans":1,"exp":"'Tu' can be used with strangers in informal settings among peers (e.g., students, young people at a party). Following the other person's lead is key. Professional contexts still require 'vous'.","lesson":"fr-clinic-register"},
  {"id":"fr-1454","topic":"fr-clinic-register","type":"gapfill","q":"Choose the formal verb for a business letter opening:","template":"Je me {0} de vous écrire afin de...","gaps":[{"options":["permets","permet","permettez","permettons"],"answer":0}],"exp":"'Je me permets de vous écrire' = I am taking the liberty of writing to you. A set formal phrase used to open professional emails and letters. 'Se permettre de' = to take the liberty of.","lesson":"fr-clinic-register"},
  {"id":"fr-1455","topic":"fr-clinic-register","type":"typed","q":"Rewrite formally: 'C'est quoi ton problème ?'","ans":"Quel est votre problème ?","alts":["quel est votre problème","Quel est votre problème","Pourriez-vous m'expliquer votre problème ?","pourriez-vous m'expliquer votre problème ?"],"ignoreAccents":true,"exp":"'C'est quoi' is informal (what is). Formal: 'Quel est' + inversion. 'Ton' → 'votre'. The formal version is also less confrontational in phrasing.","lesson":"fr-clinic-register"},
  {"id":"fr-1456","topic":"fr-clinic-register","type":"mcq","q":"Which word is more appropriate in formal writing for 'but'?","opts":["mais","cependant","bah","pis"],"ans":1,"exp":"'Cependant' (however/yet) is more formal than 'mais'. Other formal connectors: néanmoins, toutefois, or. 'Bah' and 'pis' are very informal/regional expressions.","lesson":"fr-clinic-register"},
  {"id":"fr-1457","topic":"fr-clinic-register","type":"mcq","q":"Spot the register error in a CV: 'J'ai travaillé dans beaucoup de boîtes.'","opts":["'Travaillé' should be 'travailler'.","'Beaucoup de' is too informal for a CV.","'Boîtes' is slang for companies — use 'entreprises' in formal writing.","There is no error."],"ans":2,"exp":"'Boîte' (box/tin) is slang for 'entreprise'. In a formal CV or letter, always use 'entreprise', 'société', or 'organisation'. 'Boîte' signals informal register.","lesson":"fr-clinic-register"},
  {"id":"fr-1458","topic":"fr-clinic-register","type":"gapfill","q":"Choose the correct formal verb for a professional email closing:","template":"Je vous {0} mes cordiales salutations.","gaps":[{"options":["adresse","envoie","donne","présente"],"answer":0}],"exp":"'Je vous adresse mes cordiales salutations' = I send you my cordial regards. A standard formal email closing. 'Adresser' = to direct/send (in formal writing context).","lesson":"fr-clinic-register"},
  {"id":"fr-1459","topic":"fr-clinic-register","type":"typed","q":"Write a formal single-sentence apology for not being able to attend.","ans":"Je suis malheureusement dans l'impossibilité de venir.","alts":["je suis malheureusement dans l'impossibilité de venir","Je suis dans l'impossibilité de venir.","je suis dans l'impossibilité de venir","Je ne pourrai malheureusement pas venir.","je ne pourrai malheureusement pas venir"],"ignoreAccents":true,"exp":"Formal apology: 'Je suis dans l'impossibilité de...' or 'Je ne pourrai malheureusement pas...' are both correct. Avoid 'je peux pas venir' (informal) in professional contexts.","lesson":"fr-clinic-register"},
  {"id":"fr-1460","topic":"fr-clinic-register","type":"mcq","q":"Which greeting is appropriate at the start of a professional email?","opts":["Bonjour Madame Martin,","Salut !","Yo Madame Martin,","Wesh !"],"ans":0,"exp":"'Bonjour Madame Martin,' is a common semi-formal opening. For more formal emails, 'Madame,' alone is used. 'Salut', 'Yo', and 'Wesh' are all far too informal.","lesson":"fr-clinic-register"},
  {"id":"fr-1461","topic":"fr-clinic-register","type":"mcq","q":"What does 'tutoyer' someone mean?","opts":["To speak very formally to them.","To address them as 'tu' (informal you).","To insult them indirectly.","To avoid speaking to them."],"ans":1,"exp":"'Tutoyer' = to use 'tu' with someone. 'Vouvoyer' = to use 'vous'. These verbs describe the register choice. In French culture, being asked 'On se tutoie ?' is an invitation to switch to 'tu'.","lesson":"fr-clinic-register"},
  {"id":"fr-1462","topic":"fr-clinic-register","type":"mcq","q":"Which phrase would you use to open a formal email to an unknown recipient?","opts":["Madame, Monsieur,","Coucou !","Bonjour à toi,","Hey !"],"ans":0,"exp":"'Madame, Monsieur,' is used when you don't know the recipient's gender/name. 'Coucou' and 'Hey' are informal. 'Bonjour à toi' uses 'toi' (tu form) — informal.","lesson":"fr-clinic-register"},
  {"id":"fr-1463","topic":"fr-clinic-register","type":"typed","q":"Make this polite and formal: 'Donne-moi le formulaire.'","ans":"Pourriez-vous me donner le formulaire ?","alts":["pourriez-vous me donner le formulaire","Pourriez-vous me remettre le formulaire ?","pourriez-vous me remettre le formulaire ?","Auriez-vous l'amabilité de me donner le formulaire ?"],"ignoreAccents":true,"exp":"'Donne-moi' is a blunt imperative. Polite formal: 'Pourriez-vous me donner...' (conditional + vous). Or even more formal: 'Auriez-vous l'amabilité de...'","lesson":"fr-clinic-register"},
  {"id":"fr-1464","topic":"fr-clinic-register","type":"mcq","q":"Which use of 'on' is acceptable even in formal writing?","opts":["On est allés au resto hier.","En France, on parle français.","On s'est bien marrés !","T'as vu ? On a gagné !"],"ans":1,"exp":"'On parle français' uses 'on' as a generic 'one/people' — this impersonal use is accepted in formal writing. The other examples use 'on' as a colloquial replacement for 'nous', which is informal.","lesson":"fr-clinic-register"}
];

